-- Stores benchmark runs submitted from the bakeoff live demo.
-- Results kept as JSONB so new metric fields don't require schema changes.
CREATE TABLE IF NOT EXISTS public.benchmark_runs (
    id          uuid        PRIMARY KEY DEFAULT gen_random_uuid(),
    run_type    text        NOT NULL DEFAULT 'user'
                            CHECK (run_type IN ('baseline', 'user')),
    label       text,
    ran_at      timestamptz NOT NULL DEFAULT now(),
    results     jsonb       NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_benchmark_runs_ran_at ON public.benchmark_runs (ran_at DESC);
CREATE INDEX IF NOT EXISTS idx_benchmark_runs_type   ON public.benchmark_runs (run_type);

